beforeSaveApiScript:
// ======================================================
// VARIABLES
// ======================================================
$status = entity\attribute('status');
$employeeId = entity\attribute('employeeId');
$date       = entity\attribute('date');
$clockIn    = entity\attribute('clockIn');
$clockOut   = entity\attribute('clockOut');
$reason     = entity\attribute('reason');
$assignUser = entity\attribute('assignedUserId');
$username = entity\attribute('assignedUserName');



// ======================================================
// DATE VALIDATION
// ======================================================
ifThen($date,

    $today = datetime\today();

    ifThen($date >= $today,
        recordService\throwBadRequest("Attendance request date must be before today");
    );
);



log\warning('=================== Attendance Script Triggered ====');
log\warning(string\concatenate('Assign User=: ', string\concatenate('', $assignUser)));
log\warning(string\concatenate('Status: ', string\concatenate('', $status)));
log\warning(string\concatenate('EmployeeId: ', string\concatenate('', $employeeId)));
log\warning(string\concatenate('Date: ', string\concatenate('', $date)));
log\warning(string\concatenate('ClockIn: ', string\concatenate('', $clockIn)));
log\warning(string\concatenate('ClockOut: ', string\concatenate('', $clockOut)));
log\warning(string\concatenate('Reason: ', string\concatenate('', $reason)));


// ======================================================
// APPROVED
// ======================================================
ifThen($status == 'Approved'&& $employeeId && $date,

    log\warning('APPROVED BLOCK');

    $attendanceId = record\findOne(
        'CAttendance',
        'createdAt', 'desc',
        'employeeId=', $employeeId,
        'date=', $date
    );

    log\warning(string\concatenate('Attendance ID: ', string\concatenate('', $attendanceId)));


    ifThen($attendanceId != null,

        $oldClockIn = record\attribute('CAttendance', $attendanceId, 'firstClockIn');
        $oldClockOut = record\attribute('CAttendance', $attendanceId, 'lastClockOut');
        $oldStatus = record\attribute('CAttendance', $attendanceId, 'status');

                // ======================================================
        // CALCULATION BLOCK
        // ======================================================
        $totalSeconds = null;
        $totalHoursFormatted = null;

        ifThen($clockIn && $clockOut,
            $diff = datetime\diff($clockOut, $clockIn, 'seconds');
            ifThen($diff <= 0,
                recordService\throwBadRequest("Clock Out must be greater than Clock In");
            );
            $totalSeconds = $diff;

            $hours   = ($diff - ($diff % 3600)) / 3600;
            $minutes = (($diff % 3600) - ($diff % 60)) / 60;
            $seconds = $diff % 60;

            $hh = ifThenElse($hours < 10, string\concatenate('0', $hours), $hours);
            $mm = ifThenElse($minutes < 10, string\concatenate('0', $minutes), $minutes);
            $ss = ifThenElse($seconds < 10, string\concatenate('0', $seconds), $seconds);

            $totalHoursFormatted = string\concatenate(
                string\concatenate($hh, ':'),
                string\concatenate($mm, string\concatenate(':', $ss))
            );
        );

        record\update('CAttendance', $attendanceId, 'backupClockIn', $oldClockIn);
        record\update('CAttendance', $attendanceId, 'backupClockOut', $oldClockOut);
        record\update('CAttendance', $attendanceId, 'backupStatus', $oldStatus);

        record\update('CAttendance', $attendanceId, 'firstClockIn', $clockIn);
        record\update('CAttendance', $attendanceId, 'lastClockOut', $clockOut);
        record\update('CAttendance', $attendanceId, 'status', 'Present');
        record\update('CAttendance', $attendanceId, 'assignUserId', $assignUser);

        record\update('CAttendance', $attendanceId, 'totalWorkSeconds', $totalSeconds);
        record\update('CAttendance', $attendanceId, 'totalHours', $totalHoursFormatted);


        log\warning(string\concatenate('Old ClockIn: ', string\concatenate('', $oldClockIn)));
        log\warning(string\concatenate('Old ClockOut: ', string\concatenate('', $oldClockOut)));
        log\warning(string\concatenate('Old Status: ', string\concatenate('', $oldStatus)));
        log\warning(string\concatenate('Clock In: ', string\concatenate('', $clockIn)));
        log\warning(string\concatenate('Clock Out: ', string\concatenate('', $clockOut)));
        log\warning(string\concatenate('Status: ', string\concatenate('', $status)));
        log\warning(string\concatenate('Assign User: ', string\concatenate('', $assignUser)));
        log\warning(string\concatenate('Total Seconds: ', string\concatenate('', $totalSeconds)));
        log\warning(string\concatenate('Total Hours: ', string\concatenate('', $totalHoursFormatted)));


        log\warning('Attendance updated....');
    );

    ifThen($attendanceId == null,
        // ======================================================
        // CALCULATION BLOCK
        // ======================================================
        $totalSeconds = null;
        $totalHoursFormatted = null;

        ifThen($clockIn && $clockOut,
            $diff = datetime\diff($clockOut, $clockIn, 'seconds');
            ifThen($diff <= 0,
                recordService\throwBadRequest("Clock Out must be greater than Clock In");
            );
            $totalSeconds = $diff;

            $hours   = ($diff - ($diff % 3600)) / 3600;
            $minutes = (($diff % 3600) - ($diff % 60)) / 60;
            $seconds = $diff % 60;

            $hh = ifThenElse($hours < 10, string\concatenate('0', $hours), $hours);
            $mm = ifThenElse($minutes < 10, string\concatenate('0', $minutes), $minutes);
            $ss = ifThenElse($seconds < 10, string\concatenate('0', $seconds), $seconds);

            $totalHoursFormatted = string\concatenate(
                string\concatenate($hh, ':'),
                string\concatenate($mm, string\concatenate(':', $ss))
            );
        );

        record\create('CAttendance',
            'employeeId', $employeeId,
            'name',$username,
            'date', $date,
            'firstClockIn', $clockIn,
            'lastClockOut', $clockOut,
            'totalWorkSeconds',$totalSeconds,
            'totalHours',$totalHoursFormatted,
            'status', 'Present',
            'assignedUserId',$assignUser
        );

        log\warning('New attendance created....');
    );
);


// ======================================================
// REJECTED
// ======================================================
ifThen($status == 'Rejected',

    log\warning('REJECTED BLOCK');

    $attendanceId = record\findOne(
        'CAttendance',
        'createdAt', 'desc',
        'employeeId=', $employeeId,
        'date=', $date
    );

    log\warning(string\concatenate('Attendance ID: ', string\concatenate('', $attendanceId)));

    ifThen($attendanceId != null,

        $oldClockIn = record\attribute('CAttendance', $attendanceId, 'backupClockIn');
        $oldClockOut = record\attribute('CAttendance', $attendanceId, 'backupClockOut');
        $oldStatus = record\attribute('CAttendance', $attendanceId, 'backupStatus');

        log\warning(string\concatenate('Backup ClockIn: ', string\concatenate('', $oldClockIn)));
        log\warning(string\concatenate('Backup ClockOut: ', string\concatenate('', $oldClockOut)));
        log\warning(string\concatenate('Backup Status: ', string\concatenate('', $oldStatus)));

        ifThen($oldClockIn != null || $oldClockOut != null,

            record\update('CAttendance', $attendanceId, 'firstClockIn', $oldClockIn);
            record\update('CAttendance', $attendanceId, 'lastClockOut', $oldClockOut);
            record\update('CAttendance', $attendanceId, 'status', $oldStatus);


            record\update('CAttendance', $attendanceId, 'backupClockIn', null);
            record\update('CAttendance', $attendanceId, 'backupClockOut', null);
            record\update('CAttendance', $attendanceId, 'backupClockOut', 'Present');

            $totalSeconds = null;
            $totalHoursFormatted = null;

            ifThen($oldClockIn && $oldClockOut,
                $diff = datetime\diff($clockOut, $oldClockOut, 'seconds');
                ifThen($diff <= 0,
                    recordService\throwBadRequest("Clock Out must be greater than Clock In");
                );
                $totalSeconds = $diff;

                $hours   = ($diff - ($diff % 3600)) / 3600;
                $minutes = (($diff % 3600) - ($diff % 60)) / 60;
                $seconds = $diff % 60;

                $hh = ifThenElse($hours < 10, string\concatenate('0', $hours), $hours);
                $mm = ifThenElse($minutes < 10, string\concatenate('0', $minutes), $minutes);
                $ss = ifThenElse($seconds < 10, string\concatenate('0', $seconds), $seconds);

                $totalHoursFormatted = string\concatenate(
                    string\concatenate($hh, ':'),
                    string\concatenate($mm, string\concatenate(':', $ss))
                );
            );
            record\update('CAttendance', $attendanceId, 'totalWorkSeconds', $totalSeconds);
            record\update('CAttendance', $attendanceId, 'totalHours', $totalHoursFormatted);

            log\warning('Restored from backup.....');
        );

        ifThen(
            ($oldClockIn == null && $oldClockOut == null) ||
            ($oldClockIn == '' && $oldClockOut == ''),

            ifThen($attendanceId != null,

                // OPTION 1 (Recommended - Soft delete)
                record\update('CAttendance', $attendanceId, 'deleted', true);

                // OPTION 2 (Hard delete - works in some cases)
                // record\delete('CAttendance', $attendanceId);

                log\warning('Deleted record (no backup)');
            );
        );
    );
);
